sys_script_include.script:
var AdditionalCommentWithOnHoldUpdate = Class.create();
AdditionalCommentWithOnHoldUpdate.prototype = {
    initialize: function() {
    },

	postComment: function(currState, prevState, currHoldReason, prevHoldReason, currHoldUntil, prevHoldUntil){

		var commentStr = '';
		if (currState != prevState){
			commentStr +=
				"Hello," +
				"\n\nThis is a quick update to let you know that we are temporarily placing this ticket on hold.\n\n" +
				"Reason for Hold: " + currHoldReason + "\n" +
				"Expected Follow-up Date: " + currHoldUntil  + "\n" +
				"We will provide you with another update as soon as work resumes. " +
				"If you have any questions or believe this status change was made in error, please reply directly to this comment.\n\n" +
				"Thank you for your patience.";
		} else {
			if (currHoldReason != prevHoldReason){
				commentStr += "We have updated the reason for the hold to " + currHoldReason;
				if (currHoldUntil != prevHoldUntil){
					commentStr += " and the follow-up date to " + currHoldUntil + ".";
				} else {
					commentStr += ".";
				}
			} else if (currHoldUntil != prevHoldUntil){
				commentStr += "We have updated the follow-up date to " + currHoldUntil + ".";
			}
		}
		return commentStr;
	},

    type: 'AdditionalCommentWithOnHoldUpdate'
};
